/**
 * @fileoverview Radio view — DOM setup and state effects.
 * @module module/Radio/view
 */

import { CLS, PART } from './constants.js';

/**
 * Build radio group DOM.
 *
 * @param {Elements} root
 * @param {object} config
 * @returns {{ items: Array<{ value: string, circle: Elements, dot: Elements, itemRoot: Elements }> }}
 */
export function setupDOM(root, config) {
    const { size, direction, options } = config;

    root.addClass(CLS.ROOT);
    // Reset legacy .radio styles from _utilities.sass (inherited via CLS.ROOT for token access)
    Object.assign(root[0].style, { appearance: 'unset', width: 'auto', height: 'auto', border: 'none', background: 'none', flexShrink: 'unset', verticalAlign: 'unset' });
    PART.GROUP.apply(root);

    if (direction === 'horizontal') {
        root[0].style.flexDirection = 'row';
    } else {
        root[0].style.flexDirection = 'column';
    }

    const el = root[0];
    const items = [];

    for (const opt of options) {
        // Item root
        const itemRoot = PART.ROOT.create();
        itemRoot.addClass(CLS.ROOT);
        // Reset legacy .radio styles from _utilities.sass
        Object.assign(itemRoot[0].style, { appearance: 'unset', width: 'auto', height: 'auto', border: 'none', background: 'none', flexShrink: 'unset', verticalAlign: 'unset' });
        root.append(itemRoot);

        if (size === 'sm') {
            PART.SM_ROOT.apply(itemRoot);
        } else if (size === 'lg') {
            PART.LG_ROOT.apply(itemRoot);
        }

        if (opt.disabled) itemRoot.addClass(CLS.DISABLED);

        // Circle
        const circle = PART.CIRCLE.create({
            role: 'radio',
            'aria-checked': 'false',
            tabindex: opt.disabled ? '-1' : '0',
        });
        itemRoot.append(circle);

        // Dot
        const dot = PART.DOT.create();
        circle.append(dot);

        // Label
        if (opt.label) {
            const $lbl = PART.LABEL.create();
            $lbl.text(opt.label);
            itemRoot.append($lbl);
        }

        items.push({
            value: opt.value,
            disabled: !!opt.disabled,
            circle,
            dot,
            itemRoot,
        });
    }

    return { items };
}

/**
 * Update checked visual state for all items.
 */
export function updateCheckedState(items, selectedValue) {
    for (const item of items) {
        const isChecked = item.value === selectedValue;
        if (isChecked) {
            item.circle.addClass(CLS.CHECKED);
            item.dot.addClass(CLS.CHECKED);
            item.circle[0].setAttribute('aria-checked', 'true');
        } else {
            item.circle.removeClass(CLS.CHECKED);
            item.dot.removeClass(CLS.CHECKED);
            item.circle[0].setAttribute('aria-checked', 'false');
        }
    }
}

export function cleanupDOM(root) {
    root.removeClass(CLS.GROUP);
    root[0].innerHTML = '';
}
