/**
 * @fileoverview Radio constants — CSS classes, defaults, JIT parts.
 * @module module/Radio/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    GROUP:    'radio-group',
    ROOT:     'radio',
    DOT:      'radio-dot',
    LABEL:    'radio-label',
    CIRCLE:   'radio-circle',
    CHECKED:  'is-checked',
    DISABLED: 'is-disabled',
    INVALID:  'is-invalid',
});

/** Default config for RadioGroup */
export const DEFAULTS = Object.freeze({
    name: null,
    value: null,
    disabled: false,
    size: 'md',
    direction: 'vertical',    // vertical | horizontal
    options: [],               // [{ value, label, disabled? }]
    onChange: null,
});

/** Semantic parts */
export const PART = defineParts('Radio', {
    GROUP       : { class: 'radio-group', aliases: ['group'] },
    ROOT        : { class: 'radio-container', aliases: ['root', 'container'] },
    CIRCLE      : { class: 'radio-circle', aliases: ['circle'], tag: 'span' },
    DOT         : { class: 'radio-dot', aliases: ['dot'], tag: 'span' },
    LABEL       : { class: 'radio-label', aliases: ['label'], tag: 'span' },
    SM_ROOT     : { class: 'radio-container-sm', aliases: ['sm'] },
    LG_ROOT     : { class: 'radio-container-lg', aliases: ['lg'] },
});

PART.GROUP.jit    = 'flex gap-[var(--rd-group-gap)]';
PART.ROOT.jit     = 'inline-flex items-center gap-[var(--rd-gap)] cursor-pointer select-none [font-family:var(--rd-font-stack)] text-[var(--rd-font-size)] {is-disabled}:opacity-50 {is-disabled}:cursor-not-allowed';
PART.CIRCLE.jit   = 'relative flex items-center justify-center shrink-0 w-[var(--rd-size)] h-[var(--rd-size)] rounded-full bg-[var(--rd-bg)] [border:2px_solid_var(--rd-border)] ' + TRANSITION_COLORS + ' {is-checked}:[border-color:var(--rd-checked-border)] hover:[border-color:var(--rd-hover-border)] focus-visible:[outline:2px_solid_var(--rd-checked-border)] focus-visible:[outline-offset:2px]';
PART.DOT.jit      = 'w-[var(--rd-dot-size)] h-[var(--rd-dot-size)] rounded-full bg-[var(--rd-checked-bg)] [transform:scale(0)] [transition:transform_.15s_ease] {is-checked}:[transform:scale(1)]';
PART.LABEL.jit    = 'fg-[var(--rd-text)] [line-height:1.4]';
PART.SM_ROOT.jit  = '[--rd-size:var(--rd-sm-size)] [--rd-dot-size:var(--rd-sm-dot-size)] [--rd-font-size:var(--rd-sm-font-size)]';
PART.LG_ROOT.jit  = '[--rd-size:var(--rd-lg-size)] [--rd-dot-size:var(--rd-lg-dot-size)] [--rd-font-size:var(--rd-lg-font-size)]';