/**
 * @fileoverview Radio events.
 * @module module/Radio/events
 */

import { emitEvent } from '../shared/emitEvent.js';

/**
 * Bind click/keyboard events to radio items.
 */
export function bindEvents(items, root, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    for (const item of items) {
        const handleSelect = () => {
            if (ctx.disabled() || item.disabled) return;
            ctx.select(item.value);
        };

        item.circle[0].addEventListener('click', handleSelect, opts);

        item.circle[0].addEventListener('keydown', (e) => {
            if (e.key === ' ' || e.key === 'Enter') {
                e.preventDefault();
                handleSelect();
            }
        }, opts);

        // Click on label area
        item.itemRoot[0].addEventListener('click', (e) => {
            if (e.target === item.circle[0] || item.circle[0].contains(e.target)) return;
            handleSelect();
        }, opts);
    }

    return ac;
}
